using System.Net;
using System.Net.Http.Json;
using ApiApp.DTOs;
using NUnit.Framework;

namespace ApiApp.Tests;

[TestFixture]
public class SeederTests
{
    private TestWebApplicationFactory _factory = null!;
    private HttpClient _client = null!;

    [OneTimeSetUp]
    public void OneTimeSetUp()
    {
        _factory = new TestWebApplicationFactory();
        _client = _factory.CreateClient();
    }

    [OneTimeTearDown]
    public void OneTimeTearDown()
    {
        _client.Dispose();
        _factory.Dispose();
    }

    [Test]
    public async Task Seeder_CreatesEmployees()
    {
        var response = await _client.GetAsync("/api/employees");
        var employees = await response.Content.ReadFromJsonAsync<List<EmployeeDto>>();
        Assert.That(employees!.Count, Is.GreaterThanOrEqualTo(10)); // 9 seeded + Employee 10 (Internet Sales)
    }

    [Test]
    public async Task Seeder_CreatesEmployee10_InternetSales()
    {
        var response = await _client.GetAsync("/api/employees/10");
        Assert.That(response.StatusCode, Is.EqualTo(HttpStatusCode.OK));
        var employee = await response.Content.ReadFromJsonAsync<EmployeeDto>();
        Assert.That(employee, Is.Not.Null);
        Assert.That(employee!.EmployeeId, Is.EqualTo(10));
        Assert.That(employee.WindowsUserName, Is.EqualTo("internet_sales"));
    }

    [Test]
    public async Task Seeder_CreatesCustomers()
    {
        var response = await _client.GetAsync("/api/customers");
        var customers = await response.Content.ReadFromJsonAsync<List<CustomerDto>>();
        Assert.That(customers!.Count, Is.GreaterThanOrEqualTo(6));
    }

    [Test]
    public async Task Seeder_CreatesProducts()
    {
        var response = await _client.GetAsync("/api/products");
        var products = await response.Content.ReadFromJsonAsync<List<ProductDto>>();
        Assert.That(products!.Count, Is.GreaterThanOrEqualTo(10));
    }

    [Test]
    public async Task Seeder_CreatesOrders()
    {
        var response = await _client.GetAsync("/api/orders?top=100");
        var orders = await response.Content.ReadFromJsonAsync<List<OrderSummaryDto>>();
        Assert.That(orders!.Count, Is.GreaterThanOrEqualTo(12));
    }

    [Test]
    public async Task Seeder_SeedsOrderStatusesWithCorrectIds()
    {
        var response = await _client.GetAsync("/api/orderstatuses");
        var statuses = await response.Content.ReadFromJsonAsync<List<OrderStatusDto>>();
        Assert.That(statuses!.Count, Is.EqualTo(5));
        Assert.That(statuses.Any(s => s.StatusId == 3 && s.StatusCode == "NEW"), Is.True);
    }

    [Test]
    public async Task Seeder_SeedsSystemSettings()
    {
        var response = await _client.GetAsync("/api/admin/settings");
        var settings = await response.Content.ReadFromJsonAsync<List<SystemSettingDto>>();
        Assert.That(settings, Is.Not.Empty);
        Assert.That(settings!.Any(s => s.SettingName == "TaxRate"), Is.True);
    }

    [Test]
    public async Task Seeder_IsIdempotent_DoesNotDuplicateOnRestart()
    {
        // Seeder checks for existing data before inserting
        var factory2 = new TestWebApplicationFactory();
        var client2 = factory2.CreateClient();

        // Each factory has its own db, but the important thing is seeder runs without error
        var response = await client2.GetAsync("/api/customers");
        Assert.That(response.StatusCode, Is.EqualTo(HttpStatusCode.OK));

        client2.Dispose();
        factory2.Dispose();
    }
}
